// Holdouts help establish control groups by excluding a percentage of users from seeing any experiments, allowing you to measure the overall impact of your experimentation program against a baseline.
type Holdout struct {
	// Archived Whether the holdout is archived. Archived holdouts are hidden from normal views
	// but retain their historical data and configuration.
	Archived *bool `json:"archived,omitempty"`

	// AudienceConditions Defines which audiences this holdout applies to. If omitted, the holdout applies to all users.
	// Uses logical operators like 'and', 'or', 'not' to combine multiple audience conditions.
	AudienceConditions *[]interface{} `json:"audience_conditions,omitempty"`

	// AudienceIds DEPRECATED: Use audience_conditions instead. List of audience IDs that this holdout applies to.
	// This field is maintained for backward compatibility.
	// Deprecated: this property has been marked as deprecated upstream, but no `x-deprecated-reason` was set
	AudienceIds *[]int `json:"audience_ids,omitempty"`

	// CreatedByUserEmail Email address of the user who created the holdout.
	CreatedByUserEmail *string `json:"created_by_user_email,omitempty"`

	// CreatedTime Timestamp when the holdout was originally created.
	CreatedTime *time.Time `json:"created_time,omitempty"`

	// Description Optional detailed description explaining the purpose and context of this holdout.
	// Helps team members understand what this holdout is measuring.
	Description *string `json:"description,omitempty"`

	// EndTime Timestamp when the holdout finished or will finish.
	// Null for holdouts that are still running or have no defined end time.
	EndTime *time.Time `json:"end_time,omitempty"`

	// EnvironmentKey The environment where this holdout is active (e.g., 'production', 'staging').
	// The holdout only affects traffic in this specific environment.
	EnvironmentKey *string `json:"environment_key,omitempty"`

	// HoldoutResultsApiToken API token for accessing holdout results and analytics data.
	// This token is dynamically generated for each API response and provides
	// secure access to holdout-specific results endpoints.
	HoldoutResultsApiToken *string `json:"holdout_results_api_token,omitempty"`

	// Id System-generated unique identifier for the holdout.
	Id *int `json:"id,omitempty"`

	// Key Unique user-defined identifier for the holdout within the project.
	// Must contain only alphanumeric characters, underscores, and hyphens.
	Key string `json:"key"`

	// Metrics List of metrics being tracked and analyzed for this holdout.
	// These metrics help measure the impact of experiments on the control group.
	Metrics *[]Metric `json:"metrics,omitempty"`

	// Name Human-readable name for the holdout displayed in the UI.
	Name string `json:"name"`

	// ProjectId The unique identifier of the project this holdout belongs to.
	ProjectId *int64 `json:"project_id,omitempty"`

	// Revision Revision number that increments with each change to the holdout.
	// Used for tracking modifications and ensuring data consistency.
	Revision *int `json:"revision,omitempty"`

	// Scope Defines the scope of the holdout:
	// - 'global': Affects all experiments across the entire project
	// - 'local': Affects only specific experiments or flags
	Scope *HoldoutScope `json:"scope,omitempty"`

	// ScopeType Defines how the holdout scope is applied:
	// - 'exclude': Users in holdout are excluded from seeing experiments (most common)
	// - 'include': Users in holdout are included in experiments (less common)
	ScopeType *HoldoutScopeType `json:"scope_type,omitempty"`

	// StartTime Timestamp when the holdout became or will become active.
	// When the holdout starts affecting traffic allocation.
	StartTime *time.Time `json:"start_time,omitempty"`

	// Status Current operational status of the holdout:
	// - 'draft': Holdout is configured but not yet active
	// - 'running': Holdout is currently active and affecting traffic
	// - 'concluded': Holdout has finished and is no longer active
	Status *HoldoutStatus `json:"status,omitempty"`

	// TrafficAllocation Percentage of traffic allocated to this holdout, expressed in basis points (1/100th of a percent).
	// For example: 100 = 1%, 1000 = 10%, 5000 = 50%. The remaining traffic sees experiments normally.
	TrafficAllocation *int `json:"traffic_allocation,omitempty"`

	// UpdatedTime Timestamp when the holdout was last modified.
	UpdatedTime *time.Time `json:"updated_time,omitempty"`

	// Urn Universal Resource Name (URN) for the holdout, used for global identification.
	Urn *string `json:"urn,omitempty"`
}

// HoldoutScope Defines the scope of the holdout:
// - 'global': Affects all experiments across the entire project
// - 'local': Affects only specific experiments or flags
type HoldoutScope string

// HoldoutScopeType Defines how the holdout scope is applied:
// - 'exclude': Users in holdout are excluded from seeing experiments (most common)
// - 'include': Users in holdout are included in experiments (less common)
type HoldoutScopeType string

// HoldoutStatus Current operational status of the holdout:
// - 'draft': Holdout is configured but not yet active
// - 'running': Holdout is currently active and affecting traffic
// - 'concluded': Holdout has finished and is no longer active
type HoldoutStatus string

// HoldoutExperiment Represents a single experiment rule that is connected to a holdout configuration.
//
// Contains experiment identification, timing information from the associated report,
// and the deployed variation ID if one exists for the experiment.
type HoldoutExperiment struct {
	// DeployedVariationId The unique identifier of the deployed variation for this experiment.
	// This is the Variation.id that matches the Rule.deployed_variation_key.
	// May be null if no deployed variation is configured.
	DeployedVariationId *int64 `json:"deployed_variation_id,omitempty"`

	// ExperimentEndTime The end time of the experiment report. This timestamp indicates when the
	// experiment finished collecting data. May be null for ongoing experiments.
	// Sourced from Report.end_time.
	ExperimentEndTime *time.Time `json:"experiment_end_time,omitempty"`

	// ExperimentId The layer experiment ID from the rule associated with this holdout.
	// This corresponds to the Rule.layer_experiment_id field in the database.
	ExperimentId int64 `json:"experiment_id"`

	// ExperimentStartTime The start time of the experiment report. This timestamp indicates when the
	// experiment began collecting data. Sourced from Report.start_time.
	ExperimentStartTime *time.Time `json:"experiment_start_time,omitempty"`
}

// HoldoutExperiments A collection of experiment rules associated with a holdout.
//
// Each item represents an experiment that is connected to the holdout through database
// relationships between holdouts, flags, rulesets, rules, and reports. The list contains
// experiment timing information and deployed variation details.
type HoldoutExperiments = []HoldoutExperiment

// HoldoutMap A dictionary/map of holdouts where each key is the holdout ID and the value is the holdout object.
//
// This structure is used internally for efficient lookups and when representing holdout
// relationships. The keys are string representations of holdout IDs.
type HoldoutMap map[string]Holdout

// HoldoutRequestBody Request body schema for creating or updating a holdout.
