// Holdouts are experiments that reserve a portion of your traffic to measure the impact of your feature flags and experiments. They help establish a control group by excluding a percentage of users from seeing any experiments, allowing you to measure the overall impact of your experimentation program.
type HoldoutRequestBody struct {
	// Archived Whether the holdout is archived. New holdouts are created as unarchived by default.
	Archived *bool `json:"archived,omitempty"`

	// AudienceConditions Defines which audiences this holdout should apply to. If omitted, the holdout applies to all users.
	// Uses the same structure as audience conditions in experiments - supports logical operators like 'and', 'or', 'not'.
	AudienceConditions *[]interface{} `json:"audience_conditions,omitempty"`

	// AudienceIds DEPRECATED: Use audience_conditions instead. List of audience IDs that this holdout should apply to.
	// This field is maintained for backward compatibility.
	// Deprecated: this property has been marked as deprecated upstream, but no `x-deprecated-reason` was set
	AudienceIds *[]int `json:"audience_ids,omitempty"`

	// CreatedByUserEmail Email of the user who created the holdout.
	CreatedByUserEmail *string `json:"created_by_user_email,omitempty"`

	// CreatedTime Timestamp when the holdout was created.
	CreatedTime *time.Time `json:"created_time,omitempty"`

	// Description Optional detailed description explaining the purpose and context of this holdout.
	// Helps team members understand what this holdout is measuring.
	Description *string `json:"description,omitempty"`

	// EndTime Timestamp when the holdout finished or will finish.
	EndTime *time.Time `json:"end_time,omitempty"`

	// EnvironmentKey The environment where this holdout will be active (e.g., 'production', 'staging').
	// The holdout will only affect traffic in this specific environment.
	EnvironmentKey *string `json:"environment_key,omitempty"`

	// Id System-generated unique identifier for the holdout.
	Id *int `json:"id,omitempty"`

	// Key Unique identifier for the holdout. Must be unique within the project.
	// Use alphanumeric characters, underscores, and hyphens only.
	Key string `json:"key"`

	// Metrics List of metrics that will be tracked and analyzed for this holdout.
	// These metrics help measure the impact of experiments on your control group.
	Metrics *[]Metric `json:"metrics,omitempty"`

	// Name Human-readable name for the holdout that will be displayed in the UI.
	Name string `json:"name"`

	// ProjectId The ID of the project this holdout belongs to.
	ProjectId *int64 `json:"project_id,omitempty"`

	// Revision Revision number for tracking changes to the holdout.
	Revision *int `json:"revision,omitempty"`

	// Scope Defines the scope of the holdout:
	// - 'global': Affects all experiments across the entire project
	// - 'local': Affects only specific experiments or flags (requires additional configuration)
	Scope *HoldoutRequestBodyScope `json:"scope,omitempty"`

	// ScopeType Defines how the holdout scope is applied:
	// - 'exclude': Users in holdout are excluded from seeing experiments (most common)
	// - 'include': Users in holdout are included in experiments (less common)
	ScopeType *HoldoutRequestBodyScopeType `json:"scope_type,omitempty"`

	// StartTime When the holdout should become active. If not specified, the holdout will be active immediately upon creation.
	// Must be in ISO 8601 format.
	StartTime *time.Time `json:"start_time,omitempty"`

	// Status Current status of the holdout.
	Status *HoldoutRequestBodyStatus `json:"status,omitempty"`

	// TrafficAllocation Percentage of traffic to allocate to this holdout, expressed in basis points (1/100th of a percent).
	// For example: 100 = 1%, 1000 = 10%, 5000 = 50%. The remaining traffic will see experiments normally.
	TrafficAllocation *int `json:"traffic_allocation,omitempty"`

	// UpdatedTime Timestamp when the holdout was last updated.
	UpdatedTime *time.Time `json:"updated_time,omitempty"`
}

// HoldoutRequestBodyScope Defines the scope of the holdout:
// - 'global': Affects all experiments across the entire project
// - 'local': Affects only specific experiments or flags (requires additional configuration)
type HoldoutRequestBodyScope string

// HoldoutRequestBodyScopeType Defines how the holdout scope is applied:
