// HoldoutsPaginatedList Paginated response structure for holdout collections with navigation links and metadata.
//
// This response format follows the standard pagination pattern used across the API,
// providing navigation URLs and counts for efficient browsing of large holdout collections.
type HoldoutsPaginatedList struct {
	// Count Number of holdouts returned on the current page (length of items array).
	Count int `json:"count"`

	// FilterUrl URL template for applying filters to the holdouts list. Replace the placeholder
	// with filter parameters like 'archived=false' to filter results.
	FilterUrl *UrlValue `json:"filter_url,omitempty"`

	// FirstUrl Link to the first page of holdouts in the result set. Always points to page 1
	// with the same query parameters as the current request.
	FirstUrl UrlValue `json:"first_url"`

	// Items Array of holdout objects for the current page.
	Items []Holdout `json:"items"`

	// LastUrl Link to the final page of holdouts in the result set. Points to the highest
	// page number that contains results.
	LastUrl UrlValue `json:"last_url"`

	// NextUrl Array of links to subsequent pages in the result set. The first element is the
	// immediate next page, followed by additional pages in sequence. Empty if on the last page.
	NextUrl *UrlList `json:"next_url,omitempty"`

	// Page Current page number (1-indexed). The first page is page 1, not page 0.
	// This corresponds to the requested page in the pagination sequence.
	Page int `json:"page"`

	// PrevUrl Array of links to previous pages in the result set. The first element is the
	// immediate previous page, followed by earlier pages in reverse sequence. Empty if on the first page.
	PrevUrl *UrlList `json:"prev_url,omitempty"`

	// ResetUrl Link to reset pagination and view the default first page without any applied filters.
	// Use this to return to the standard holdouts list view.
	ResetUrl *UrlValue `json:"reset_url,omitempty"`

	// TotalCount Total number of holdouts matching the query criteria across all pages.
	// This count reflects any filters applied to the request.
	TotalCount int `json:"total_count"`

	// TotalPages Total number of pages required to display all holdouts matching the criteria.
	// Calculated as ceil(total_count / per_page).
	TotalPages int `json:"total_pages"`

	// Url Link to the current page (self-reference). Use this URL to refresh
	// the current page or bookmark the current view.
	Url UrlValue `json:"url"`
}

// Metric defines model for Metric.
type Metric struct {
	// Aggregator The aggregation function for the numerator of the metric. 'unique' measures the number of unique visitors/sessions that include the specified Event. 'count' measures the total number of occurrences of Event for the scope (visitor/session). 'sum' is the sum of the 'field' value
	Aggregator MetricAggregator `json:"aggregator"`

	// DisplayTitle An optional title for the unique metric configuration. If not provided, the event name will be used.
	DisplayTitle *string `json:"display_title,omitempty"`

	// DisplayUnit An optional name for the unit of the unique metric configuration.
	DisplayUnit *string `json:"display_unit,omitempty"`

	// EventId The ID for the Event to select data from. Omitted for global metrics that are not relative to a specific Event, i.e. "overall revenue"
	EventId         *int64 `json:"event_id,omitempty"`
	EventProperties *struct {
		Filter *struct {
			CombineOperator *MetricEventPropertiesFilterCombineOperator `json:"combine_operator,omitempty"`
			Conditions      interface{}                                 `json:"conditions,omitempty"`
		} `json:"filter,omitempty"`
	} `json:"event_properties,omitempty"`
	EventType *string `json:"event_type,omitempty"`

	// Field The field to aggregate for the numerator of the metric. Required when 'aggregator' = 'sum', otherwise omitted
	Field *MetricField `json:"field,omitempty"`

	// Id A unique identifier for the metric configuration.
	Id      *string      `json:"id,omitempty"`
	Metrics *[]SubMetric `json:"metrics,omitempty"`

	// ProjectId A unique identifier for the project associated with the metric.
	ProjectId *int `json:"project_id,omitempty"`

	// Scope Specifies how Events should be grouped together. Can also be thought of as the denonimator of the metric. 'session' divides by the number of sessions. "Influenced sessions", or sessions that do not contain a decision Event but carry a decision from a previous session are not included in counts for numerator or denominator. 'visitor' divides by the number of visitors. 'event' divides by the total occurrences (impressions) of the specified Event
	Scope *MetricScope `json:"scope,omitempty"`

	// Visibility The visibility of the metric.
	Visibility *MetricVisibility `json:"visibility,omitempty"`

	// WinningDirection The winning direction of this metric
	WinningDirection MetricWinningDirection `json:"winning_direction"`
}

// MetricAggregator The aggregation function for the numerator of the metric. 'unique' measures the number of unique visitors/sessions that include the specified Event. 'count' measures the total number of occurrences of Event for the scope (visitor/session). 'sum' is the sum of the 'field' value
